Here's a complete MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        using var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello world"),
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_ErrorStatus_ThrowsHttpRequestException()
    {
        // Arrange
        using var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel
        using var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.OK));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_WithTimeout_CompletesBeforeDeadline()
    {
        // Arrange
        using var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("fast response"),
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act — pass TestContext.CancellationToken so [Timeout] can cancel cooperatively
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("fast response", result);
    }

    [TestMethod]
    [Timeout(1000)]
    public async Task FetchAsync_SlowResponse_CancelledByTimeout()
    {
        // Arrange — handler delays longer than the [Timeout]
        using var handler = new MockHandler(delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert — the [Timeout] fires, cancelling TestContext.CancellationToken
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    // Minimal test double for HttpMessageHandler
    private sealed class MockHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        private readonly TimeSpan _delay;

        public MockHandler(HttpResponseMessage? response = null, TimeSpan delay = default)
        {
            _response = response ?? new HttpResponseMessage(HttpStatusCode.OK);
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
            {
                await Task.Delay(_delay, cancellationToken);
            }

            return _response;
        }
    }
}
```

**Key patterns used:**

- **`TestContext` via constructor injection** — enables `readonly` and satisfies nullability
- **`TestContext.CancellationToken`** — cooperates with `[Timeout]` so slow tests are cancelled cleanly instead of hanging
- **`Assert.ThrowsExactlyAsync<T>`** — verifies the exact exception type (not `[ExpectedException]`)
- **`MockHandler`** — lightweight `HttpMessageHandler` stub with optional delay for timeout tests
- **Sealed test class** — best practice for performance
- **Pre-cancelled token test** — proves `FetchAsync` respects cancellation immediately

The `SlowResponse_CancelledByTimeout` test is the critical one: the `[Timeout(1000)]` attribute fires after 1 second, which cancels `_testContext.CancellationToken`, which propagates into `HttpClient.GetAsync` and throws `TaskCanceledException`.
